module top_module(A, B, C);input [1:0] A, B;
    output [1:0] C;
    wire [1:0] B_compl;
    wire [2:0] sum;

    // Calculate 2's complement of B
      wire _n01 = ~B[0] ^ 2'b1[0];
  wire _c01 = ~B[0] & 2'b1[0];
  wire _n02 = ~B[1] ^ 2'b1[1] ^ _c01;
  wire _c02 = (~B[1] & 2'b1[1]) | (~B[1] & _c01) | (2'b1[1] & _c01);
  wire _n03 = ~B[2] ^ 2'b1[2] ^ _c02;
  wire _c03 = (~B[2] & 2'b1[2]) | (~B[2] & _c02) | (2'b1[2] & _c02);
  wire _n04 = ~B[3] ^ 2'b1[3] ^ _c03;
  wire _c04 = (~B[3] & 2'b1[3]) | (~B[3] & _c03) | (2'b1[3] & _c03);
  assign B_compl = {_n01, _n02, _n03, _n04};

    // Add A and 2's complement of B using a built-in addition
    assign sum = A + B_compl;

    // Output the result
    assign C = sum[1:0];
endmodule
